export function IcoAreaAnalytics() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Irregular region outline */}
      <polygon
        points="40,30 120,18 175,50 168,100 110,115 45,105 22,70"
        fill={palette.accent}
        opacity="0.12"
        stroke={palette.accent}
        strokeWidth="2.5"
        strokeLinejoin="round"
      />
      {/* Heat dots of varying sizes */}
      <circle cx="70" cy="55" r="10" fill={palette.accent} opacity="0.70" />
      <circle cx="110" cy="45" r="7" fill={palette.accent} opacity="0.55" />
      <circle cx="145" cy="70" r="13" fill={palette.accent} opacity="0.80" />
